var closest=context.state.proximity[0]||{};
var front=context.state.scanner.robot[0]||false;
var rem=context.round.remaining;
var myX=context.state.position.x,myY=context.state.position.y;
var dC=Math.sqrt((myX-450)*(myX-450)+(myY-450)*(myY-450));
if(rem<5){
