  else{context.action.desiredForce=0;}
}else if(rem<12){
  context.action.desiredAngle=context.state.angleToCenter;
  context.action.desiredForce=context.state.maxForce;
  if(front&&front.active&&front.team!=context.state.team)context.action.desiredLaunch=true;
}else if(closest.entityType=="wall"){
  context.action.desiredAngle=context.state.angleToCenter;
}else if(front){
  if(front.active&&front.team!=context.state.team){
    context.action.desiredAngle=front.angleFromRobot;
    context.action.desiredLaunch=true;
  }else{
    var dir2=(front.angleFromRobot-context.state.angle)<0?-1:1;
    context.action.desiredAngle=context.state.angle-(dir2*0.174533);
  }
}else if(dC>280){
  context.action.desiredAngle=context.state.angleToCenter;
}else if(Math.random()<0.015){
  var maxvar=Math.PI/3;
  context.action.desiredAngle=context.state.angle+(Math.random()*maxvar)-maxvar/2;
}
